async (params, browser) => {
  // Open historical data page
  await browser.open(`https://finance.yahoo.com/quote/${params.symbol}/history/`)

  // Wait for history table to load
  await browser.waitForSelector('table tbody tr, [data-testid=\'history-table\'], [class*=\'historical\']', 15000)

  // Let table render
  await browser.wait(2000)

  // Scroll to load more rows
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract historical price data
  const history_data = await browser.evaluate(`const history = []; const rows = document.querySelectorAll('table tbody tr'); for (let i = 0; i < Math.min(rows.length, 30); i++) { const row = rows[i]; const cells = row.querySelectorAll('td'); if (cells.length >= 6) { history.push({ date: cells[0] ? cells[0].textContent.trim() : '', open: cells[1] ? cells[1].textContent.trim() : '', high: cells[2] ? cells[2].textContent.trim() : '', low: cells[3] ? cells[3].textContent.trim() : '', close: cells[4] ? cells[4].textContent.trim() : '', adj_close: cells[5] ? cells[5].textContent.trim() : '', volume: cells[6] ? cells[6].textContent.trim() : '' }); } } const nameEl = document.querySelector('h1, [class*="quote-header"] h1'); return { symbol: '' + params.symbol + '', name: nameEl ? nameEl.textContent.trim() : '', data_points: history.length, history: history, url: window.location.href }`)

  return history_data
}
